import * as fs from 'fs';
import * as os from 'os';
import * as path from 'path';
import { rimraf } from 'rimraf';
import { Dirty } from '../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js';

describe('Dirty drain event after write stream drain', () => {
  it('should emit drain event when write stream drains with empty queue and no in-flight writes', (done) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
    const dbPath = path.join(tmpDir, 'test.db');

    const db = new Dirty(dbPath);

    db.on('load', () => {
      // Intercept the write stream to simulate backpressure
      const ws = db._writeStream;
      const originalWrite = ws.write.bind(ws);

      let forcedDrain = false;
      ws.write = function(data, cb) {
        if (!forcedDrain) {
          forcedDrain = true;
          // Call original but return false to simulate backpressure
          originalWrite(data, cb);
          return false;
        }
        return originalWrite(data, cb);
      };

      db.on('drain', () => {
        db.close();
      });

      db.on('write_close', () => {
        rimraf(tmpDir).then(() => done()).catch(done);
      });

      db.set('key1', { value: 'test' });
    });

    db.on('error', done);

    setTimeout(() => done(new Error('Timeout: drain event never fired')), 5000);
  });
});
